// === Parser logs Belcorp: Separador + Bandeja (InterfazTXT) ===
// Modo: Run Once for All Items. Recibe 2 items (un log cada uno) desde Extract from File.
// FILOSOFIA FAIL-SAFE: ante ambiguedad avisamos. Preferimos falsa alarma a omitir un error.

const dt = (s) => {
  const [d, t] = String(s).split(' ');
  const [dd, mm, yy] = d.split('/');
  return new Date(`${yy}-${mm}-${dd}T${t || '00:00:00'}`);
};

// --- 1. Clasificar logs por contenido (robusto al nombre de campo) ---
let sepLog = '', banLog = '';
for (const it of $input.all()) {
  const txt = it.json.data ?? it.json.text ?? it.json.fileContent ?? '';
  if (/Inicio parseador documentos/i.test(txt)) sepLog += '\n' + txt;
  else if (/Inicio Procesado Comprobantes/i.test(txt)) banLog += '\n' + txt;
}

// --- 2. Separador: bloque por archivo, ULTIMA corrida gana ---
function parseSeparador(txt) {
  const bloques = txt.split(/(?=Inicio parseador documentos:)/g).map(b => b.trim()).filter(Boolean);
  const porArchivo = new Map();
  let reprocesos = 0, truncas = 0;

  for (const b of bloques) {
    const mFile = b.match(/Inicio parseador documentos:\s*(.+?)\s*\.\.\.\s*(\d{2}\/\d{2}\/\d{4} \d{2}:\d{2}:\d{2})/);
    if (!mFile) continue;
    const archivo = mFile[1].trim();
    const ts = dt(mFile[2]);

    const mOk  = b.match(/Parseados Correctamente\s*:\s*(\d+)/i);
    const mErr = b.match(/Con error:\s*(\d+)/i);
    if (!mOk && !mErr) { truncas++; continue; } // corrida cortada (posible caida de servicio)

    const ok  = mOk  ? parseInt(mOk[1], 10)  : 0;
    const err = mErr ? parseInt(mErr[1], 10) : 0;

    const detalles = [];
    const re = /Codigo:\s*([^,]*),\s*Nombre:\s*(.+?),\s*Nit:\s*([^,]*),.*?ERROR DE FORMATO:\s*(.+?)(?=\n|Fin parseador|$)/gis;
    let m;
    while ((m = re.exec(b)) !== null) {
      detalles.push({ codigo: m[1].trim(), nombre: m[2].trim(), nit: m[3].trim(), error: m[4].trim() });
    }

    const prev = porArchivo.get(archivo);
    if (prev) reprocesos++;
    if (!prev || ts >= prev.ts) porArchivo.set(archivo, { ts, ok, err, detalles });
  }

  let exitosos = 0, errores = 0, detalles = [];
  for (const v of porArchivo.values()) { exitosos += v.ok; errores += v.err; detalles.push(...v.detalles); }
  return { exitosos, errores, detalles, reprocesos, truncas, archivos: porArchivo.size };
}

// --- 3. Bandeja: estado final por comprobante (ULTIMA aparicion gana) ---
function parseBandeja(txt) {
  const bloques = txt.split(/(?=Inicio Procesado Comprobantes)/g).map(b => b.trim()).filter(Boolean);
  const porSap = new Map();      // clave SAP (o codigo) -> estado final
  const porCodigo = new Map();   // indice por codigo de cliente, para cruzar con Separador
  let bloquesConError = 0;

  for (const b of bloques) {
    const mTs = b.match(/Inicio Procesado Comprobantes\s*(\d{2}\/\d{2}\/\d{4} \d{2}:\d{2}:\d{2})/);
    const bTs = mTs ? dt(mTs[1]) : new Date(0);
    const mErr = b.match(/con error:\s*(\d+)/i);
    if (mErr && parseInt(mErr[1], 10) > 0) bloquesConError++;

    for (const p of b.split(/Se proceso Comprobante:/i).slice(1)) {
      const sap    = (p.match(/SAP:\s*(\d+)/i)     || [])[1] || '';
      const codigo = (p.match(/digo:\s*(\d+)/i)    || [])[1] || ''; // 'Codigo:' antes del SAP
      const nombre = (p.match(/Nombre:\s*(.+?),/i) || [])[1] || '';
      const nit    = (p.match(/Nit:\s*(\d+)/i)     || [])[1] || '';
      const error  = ((p.match(/Error:\s*(.+?)(?:\n|$)/i) || [])[1] || '').trim();
      const key = sap || codigo;
      if (!key) continue;
      const tipo = /ya existe/i.test(error) ? 'duplicado' : 'real';
      const rec = { sap, codigo, nombre: nombre.trim(), nit, error, tipo, ts: bTs };
      const prev = porSap.get(key);
      if (!prev || bTs >= prev.ts) porSap.set(key, rec);
      if (codigo) {
        const prevC = porCodigo.get(codigo);
        if (!prevC || bTs >= prevC.ts) porCodigo.set(codigo, rec);
      }
    }
  }

  const vals = [...porSap.values()];
  return {
    erroresReales: vals.filter(x => x.tipo === 'real'),
    duplicados:    vals.filter(x => x.tipo === 'duplicado'),
    porCodigo,
    bloquesConError,
  };
}

// --- 4. CRUCE Separador <-> Bandeja (fail-safe) ---
const sep = parseSeparador(sepLog);
const ban = parseBandeja(banLog);

// Un error de formato del Separador (en su ultima corrida) puede haberse resuelto:
// si ese mismo codigo aparece en Bandeja con estado final NO-error, llego a comfiar.
const sepErroresConfirmados = []; // no recuperados -> error duro
const sepErroresResueltos   = []; // reprocesados OK segun Bandeja
for (const e of sep.detalles) {
  const enBandeja = e.codigo ? ban.porCodigo.get(e.codigo) : null;
  if (enBandeja && enBandeja.tipo !== 'real') sepErroresResueltos.push(e);
  else sepErroresConfirmados.push(e); // fail-safe: si no lo confirmo, es error
}

// --- 5. Consolidar estado ---
const erroresDuros = sepErroresConfirmados.length + ban.erroresReales.length;

// Ambiguedad: no es error duro, pero amerita revision humana
const ambiguo =
  sep.reprocesos > 0 || sep.truncas > 0 ||
  ban.duplicados.length > 0 || sepErroresResueltos.length > 0;

const universo = sep.exitosos;                          // docs separados OK (denominador)
const cargados = universo - ban.erroresReales.length;   // estimados en comfiar

let estado = 'OK';
if (erroresDuros > 0) estado = 'ERROR';
else if (ambiguo) estado = 'REVISAR';
// Si falto leer un log, no podemos afirmar que todo esta OK
if ((!sepLog || !banLog) && estado !== 'ERROR') estado = 'REVISAR';

const hayErrores = estado !== 'OK';

// --- 6. Mensaje Teams (HTML) ---
const fecha = $node['Calcular Fechas1']?.json?.fechaDisplay || new Date().toLocaleDateString('es-AR');
const MAX = 15;
const icono = estado === 'ERROR' ? '🔴' : estado === 'REVISAR' ? '🟡' : '🟢';
const lista = (arr, fn) => arr.slice(0, MAX).map(fn).join('<br>') +
  (arr.length > MAX ? `<br>… +${arr.length - MAX} mas` : '');

let msg = `${icono} <b>Reporte Belcorp — ${fecha}</b> — <b>${estado}</b><br><br>`;
msg += `📄 Documentos (Separador): <b>${universo}</b><br>`;
msg += `☁️ Estimados en comfiar: <b>${cargados}</b><br>`;
msg += `🔴 Errores a resolver: <b>${erroresDuros}</b><br>`;

if (sepErroresConfirmados.length) {
  msg += `<br><b>Separador — no se separaron (${sepErroresConfirmados.length}):</b><br>`;
  msg += lista(sepErroresConfirmados, d => `• Cod ${d.codigo} (NIT ${d.nit}) ${d.nombre} — ${d.error}`) + '<br>';
}
if (ban.erroresReales.length) {
  msg += `<br><b>Bandeja — no cargaron a comfiar (${ban.erroresReales.length}):</b><br>`;
  msg += lista(ban.erroresReales, d => `• SAP ${d.sap} / Cod ${d.codigo} (NIT ${d.nit}) — ${d.error}`) + '<br>';
}

// Zona informativa: ambiguedades (no son errores duros, pero avisamos)
const notas = [];
if (sepErroresResueltos.length) notas.push(`${sepErroresResueltos.length} error(es) de separacion se reprocesaron OK (llegaron a comfiar).`);
if (ban.duplicados.length)      notas.push(`${ban.duplicados.length} comprobante(s) marcados "ya existe": reprocesamiento, presuntamente ya cargados.`);
if (sep.reprocesos)             notas.push(`${sep.reprocesos} corrida(s) repetida(s) del mismo archivo en Separador.`);
if (sep.truncas)                notas.push(`${sep.truncas} corrida(s) del Separador quedaron cortadas (posible caida de servicio).`);
if (notas.length) {
  msg += `<br><b>⚠️ A revisar (ambiguedades):</b><br>` + notas.map(n => `• ${n}`).join('<br>') + '<br>';
  msg += `<i>Si los numeros no cuadran, validar contra comfiar: SELECT codigoerp, resultado, errordesc FROM comprobante WITH(NOLOCK) WHERE cuitid=1028501021.</i><br>`;
}
if (estado === 'OK') msg += `<br><b>Todo procesado sin novedades.</b>`;

if (!sepLog) msg += `<br>🟡 <b>No se pudo leer el log del Separador.</b>`;
if (!banLog) msg += `<br>🟡 <b>No se pudo leer el log de la Bandeja.</b>`;

return [{
  json: {
    fecha, estado, hayErrores,
    universo, cargados, erroresDuros,
    mensaje: msg,
    reporte: {
      separador: { exitosos: sep.exitosos, errores: sep.errores, reprocesos: sep.reprocesos, truncas: sep.truncas,
                   erroresConfirmados: sepErroresConfirmados, erroresResueltos: sepErroresResueltos },
      bandeja: { erroresReales: ban.erroresReales, duplicados: ban.duplicados.length },
    },
  },
}];
